static void lud_diagonal(float *m, int matrix_dim, int offset)
{
  int i,j;

  float shadow[BLOCK_SIZE][BLOCK_SIZE];

  int array_offset = offset*matrix_dim+offset;
  for(i=0; i < BLOCK_SIZE; i++){
    #pragma omp simd
    for (int tx = 0; tx < BLOCK_SIZE; tx++)
      shadow[i][tx]=m[array_offset+tx];
    array_offset += matrix_dim;
  }

  for(i=0; i < BLOCK_SIZE-1; i++) {

    #pragma omp parallel for private(j) shared(shadow,i) default(none)
    for(int tx=0; tx < BLOCK_SIZE; tx++) {
      if (tx>i){
        for(j=0; j < i; j++)
          shadow[tx][i] -= shadow[tx][j]*shadow[j][i];
        shadow[tx][i] /= shadow[i][i];
      }
    }

    #pragma omp barrier

    #pragma omp parallel for private(j) shared(shadow,i) default(none)
    for(int tx=0; tx < BLOCK_SIZE; tx++) {
      if (tx>i){
        for(j=0; j < i+1; j++)
          shadow[i+1][tx] -= shadow[i+1][j]*shadow[j][tx];
      }
    }
    #pragma omp barrier
  }

  array_offset = (offset+1)*matrix_dim+offset;
  for(i=1; i < BLOCK_SIZE; i++){
    #pragma omp simd
    for (int tx = 0; tx < BLOCK_SIZE; tx++)
      m[array_offset+tx]=shadow[i][tx];
    array_offset += matrix_dim;
  }
}

static void lud_perimeter(float *m, int matrix_dim, int offset, int blockIdx_x)
{
  float dia[BLOCK_SIZE][BLOCK_SIZE];
  float peri_row[BLOCK_SIZE][BLOCK_SIZE];
  float peri_col[BLOCK_SIZE][BLOCK_SIZE];

  int i,j, array_offset;

  #pragma omp parallel for
  for(int tx=0; tx < BLOCK_SIZE*2; tx++) {
    int idx;
    if (tx < BLOCK_SIZE) {
      idx = tx;
      array_offset = offset*matrix_dim+offset;
      for (i=0; i < BLOCK_SIZE/2; i++){
        dia[i][idx]=m[array_offset+idx];
        array_offset += matrix_dim;
      }

      array_offset = offset*matrix_dim+offset;
      for (i=0; i < BLOCK_SIZE; i++) {
        peri_row[i][idx]=m[array_offset+(blockIdx_x+1)*BLOCK_SIZE+idx];
        array_offset += matrix_dim;
      }
    } else {
      idx = tx-BLOCK_SIZE;
      array_offset = (offset+BLOCK_SIZE/2)*matrix_dim+offset;
      for (i=BLOCK_SIZE/2; i < BLOCK_SIZE; i++){
        dia[i][idx]=m[array_offset+idx];
        array_offset += matrix_dim;
      }

      array_offset = (offset+(blockIdx_x+1)*BLOCK_SIZE)*matrix_dim+offset;
      for (i=0; i < BLOCK_SIZE; i++) {
        peri_col[i][idx] = m[array_offset+idx];
        array_offset += matrix_dim;
      }
    }
  }

  #pragma omp barrier

  #pragma omp parallel for private(i,j) shared(peri_row,dia) default(none)
  for(int tx=0; tx < BLOCK_SIZE; tx++) {
    for(i=1; i < BLOCK_SIZE; i++){
      for (j=0; j < i; j++)
        peri_row[i][tx]-=dia[i][j]*peri_row[j][tx];
    }
  }

  #pragma omp parallel for private(i,j) shared(peri_col,dia) default(none)
  for(int tx=0; tx < BLOCK_SIZE; tx++) {
    for(i=0; i < BLOCK_SIZE; i++){
      for(j=0; j < i; j++)
        peri_col[tx][i]-=peri_col[tx][j]*dia[j][i];
      peri_col[tx][i] /= dia[i][i];
    }
  }

  #pragma omp barrier

  #pragma omp parallel for
  for(int tx=0; tx < BLOCK_SIZE*2; tx++) {
    int idx;
    int array_offset;
    if (tx < BLOCK_SIZE) {
      idx=tx;
      array_offset = (offset+1)*matrix_dim+offset;
      for(i=1; i < BLOCK_SIZE; i++){
        m[array_offset+(blockIdx_x+1)*BLOCK_SIZE+idx] = peri_row[i][idx];
        array_offset += matrix_dim;
      }
    } else {
      idx=tx - BLOCK_SIZE;
      array_offset = (offset+(blockIdx_x+1)*BLOCK_SIZE)*matrix_dim+offset;
      for(i=0; i < BLOCK_SIZE; i++){
        m[array_offset+idx] =  peri_col[i][idx];
        array_offset += matrix_dim;
      }
    }
  }
}

static void lud_internal(float *m, int matrix_dim, int offset, int blockIdx_x, int blockIdx_y)
{
  float peri_row[BLOCK_SIZE][BLOCK_SIZE];
  float peri_col[BLOCK_SIZE][BLOCK_SIZE];

  int i;

  int global_row_id = offset + (blockIdx_y+1)*BLOCK_SIZE;
  int global_col_id = offset + (blockIdx_x+1)*BLOCK_SIZE;

  #pragma omp parallel for collapse(2)
  for(int ty=0; ty < BLOCK_SIZE; ty++) {
    for(int tx=0; tx < BLOCK_SIZE; tx++) {
      peri_row[ty][tx] = m[(offset+ty)*matrix_dim+global_col_id+tx];
      peri_col[ty][tx] = m[(global_row_id+ty)*matrix_dim+offset+tx];
    }
  }

  #pragma omp barrier

  #pragma omp parallel for private(i) collapse(2)
  for(int ty=0; ty < BLOCK_SIZE; ty++) {
    for(int tx=0; tx < BLOCK_SIZE; tx++) {
      float sum = 0;
      for (i=0; i < BLOCK_SIZE; i++)
        sum += peri_col[ty][i] * peri_row[i][tx];
      m[(global_row_id+ty)*matrix_dim+global_col_id+tx] -= sum;
    }
  }
}

void lud_cuda(float *m, int matrix_dim)
{
  int i=0;

  for (i=0; i < matrix_dim-BLOCK_SIZE; i += BLOCK_SIZE) {
      lud_diagonal(m, matrix_dim, i);

      int perimeter_blocks = (matrix_dim - i)/BLOCK_SIZE - 1;
      #pragma omp parallel for
      for (int b=0; b < perimeter_blocks; b++) {
          lud_perimeter(m, matrix_dim, i, b);
      }

      int inner_blocks = perimeter_blocks;
      #pragma omp parallel for collapse(2)
      for (int by=0; by < inner_blocks; by++) {
        for (int bx=0; bx < inner_blocks; bx++) {
          lud_internal(m, matrix_dim, i, bx, by);
        }
      }
  }
  lud_diagonal(m, matrix_dim, i);
}
